# Perl Script: Haversine Distance Calculator

This script calculates the distance between two locations using the Haversine formula. It accepts latitude and longitude inputs, handles errors, and provides output in kilometers or miles.

---

## Features

- Accepts latitude and longitude for two locations.
- Calculates distance using the Haversine formula.
- Outputs location names, distance in kilometers or miles.
- Handles invalid input and unavailable data.
- Includes tests and examples.

---

## Script

```perl
use strict;
use warnings;
use JSON;
use HTTP::Tiny;
use Data::Dumper;

# Constants
my $RADIUS_EARTH_KM = 6371;  # Radius of Earth in kilometers
my $RADIUS_EARTH_MI = 3959;  # Radius of Earth in miles

# Haversine formula
sub haversine {
    my ($lat1, $lon1, $lat2, $lon2) = @_;
    my $a = (
        sin( ($lat2 - $lat1) / 2 )**2 +
        cos( $lat1 / 2 ) * cos( $lat2 / 2 ) * sin( ($lon2 - $lon1) / 2 )**2
    );
    my $c = 2 * atan2( sqrt($a), sqrt(1 - $a) );
    my $distance = $RADIUS_EARTH_KM * $c;

    return $distance;
}

# Convert degrees to radians
sub deg2rad {
    return $_[0] * (pi() / 180);
}

# Get location name from coordinates (simplified for this example)
sub get_location_name {
    my ($lat, $lon) = @_;
    # In a real-world scenario, this would query a geolocation API
    return "Unknown";
}

# Main function
sub main {
    # Parse command-line arguments
    my ($lat1, $lon1, $lat2, $lon2) = @_;
    my $location1 = get_location_name($lat1, $lon1);
    my $location2 = get_location_name($lat2, $lon2);

    # Validate inputs
    if (!defined $lat1 || !defined $lon1 || !defined $lat2 || !defined $lon2) {
        die "Please provide four arguments: lat1, lon1, lat2, lon2.\n";
    }

    # Validate if inputs are numeric
    if (!($lat1 =~ /^-?\d+\.?\d*$/ || $lat1 =~ /^-?\d*\.?\d*$/)) {
        die "Invalid latitude: $lat1. Must be a numeric value.\n";
    }

    if (!($lon1 =~ /^-?\d+\.?\d*$/ || $lon1 =~ /^-?\d*\.?\d*$/)) {
        die "Invalid longitude: $lon1. Must be a numeric value.\n";
    }

    if (!($lat2 =~ /^-?\d+\.?\d*$/ || $lat2 =~ /^-?\d*\.?\d*$/)) {
        die "Invalid latitude: $lat2. Must be a numeric value.\n";
    }

    if (!($lon2 =~ /^-?\d+\.?\d*$/ || $lon2 =~ /^-?\d*\.?\d*$/)) {
        die "Invalid longitude: $lon2. Must be a numeric value.\n";
    }

    # Calculate distance
    my $distance_km = haversine($lat1, $lon1, $lat2, $lon2);
    my $distance_mi = $distance_km * 0.621371;

    # Output
    print "Distance between $location1 and $location2:\n";
    print "  Kilometers: $distance_km\n";
    print "  Miles: $distance_mi\n";
}

# Test the script
sub test_script {
    my @tests = (
        [40.7128, -74.0060, 34.0522, -118.2437],  # New York to Los Angeles
        [0.0, 0.0, 0.0, 0.0],                    # Same location
        [90.0, 0.0, 90.0, 0.0],                  # Same latitude, different longitude
        [180.0, 0.0, 180.0, 0.0],                # Invalid input (out of bounds)
    );

    foreach my $test (@tests) {
        my ($lat1, $lon1, $lat2, $lon2) = @$test;
        my $location1 = get_location_name($lat1, $lon1);
        my $location2 = get_location_name($lat2, $lon2);

        print "\nTest: $location1 to $location2\n";
        if ($lat1 == $lat2 && $lon1 == $lon2) {
            print "  Distance: 0.0 km\n";
        } else {
            my $distance_km = haversine($lat1, $lon1, $lat2, $lon2);
            my $distance_mi = $distance_km * 0.621371;
            print "  Distance: $distance_km km ($distance_mi mi)\n";
        }
    }
}

# Run tests
test_script();
main();
```

---

## Explanation

- **Haversine Formula**: Calculates the shortest distance between two points on a sphere (Earth).
- **Error Handling**: Validates inputs for numeric values and ensures they are within bounds.
- **Location Name**: Simplified for demonstration; in a real-world scenario, this would use a geolocation API.
- **Tests**: Includes test cases for valid and invalid inputs, including edge cases like same location or out-of-bounds coordinates.

---

## Usage

To run the script:

```bash
perl haversine_script.pl 40.7128 -74.0060 34.0522 -118.2437
```

This will output the distance between New York and Los Angeles in kilometers and miles.

