// BinarySearchTree.swift
import Foundation

// Define a Node struct to represent each node in the BST
struct Node {
    let value: Int
    let left: Node?
    let right: Node?

    init(_ value: Int) {
        self.value = value
        self.left = nil
        self.right = nil
    }
}

// Define the BST class
class BinarySearchTree {
    var root: Node?

    // Insert a new node into the BST
    func insert(_ value: Int) {
        root = insertNode(root, value)
    }

    private func insertNode(_ node: Node?, _ value: Int) -> Node? {
        if node == nil {
            return Node(value)
        }

        if value < node!.value {
            node!.left = insertNode(node!.left, value)
        } else if value > node!.value {
            node!.right = insertNode(node!.right, value)
        }

        return node!
    }

    // Delete a node from the BST
    func delete(_ value: Int) {
        root = deleteNode(root, value)
    }

    private func deleteNode(_ node: Node?, _ value: Int) -> Node? {
        if node == nil {
            return nil
        }

        if value < node!.value {
            node!.left = deleteNode(node!.left, value)
        } else if value > node!.value {
            node!.right = deleteNode(node!.right, value)
        } else {
            // Node found, handle deletion
            if node!.left == nil {
                return node!.right
            } else if node!.right == nil {
                return node!.left
            } else {
                // Node has two children, find the in-order successor
                let successor = findInOrderSuccessor(node!.right)
                node!.value = successor.value
                node!.right = deleteNode(node!.right, successor.value)
            }
        }

        return node!
    }

    private func findInOrderSuccessor(_ node: Node?) -> Node? {
        var current = node
        var successor = nil

        // Find the in-order successor
        while current != nil {
            if current!.value > successor!.value {
                successor = current!
            }
            current = current!.left
        }

        return successor
    }

    // Traverse the BST in pre-order
    func preOrderTraverse() {
        preOrderTraverse(root, "")
    }

    private func preOrderTraverse(_ node: Node?, _ traversal: String) {
        if node != nil {
            print(traversal + node!.value)
            preOrderTraverse(node!.left, traversal + "left")
            preOrderTraverse(node!.right, traversal + "right")
        }
    }

    // Traverse the BST in in-order
    func inOrderTraverse() {
        inOrderTraverse(root, "")
    }

    private func inOrderTraverse(_ node: Node?, _ traversal: String) {
        if node != nil {
            inOrderTraverse(node!.left, traversal + "left")
            print(traversal + node!.value)
            inOrderTraverse(node!.right, traversal + "right")
        }
    }

    // Traverse the BST in post-order
    func postOrderTraverse() {
        postOrderTraverse(root, "")
    }

    private func postOrderTraverse(_ node: Node?, _ traversal: String) {
        if node != nil {
            postOrderTraverse(node!.left, traversal + "left")
            postOrderTraverse(node!.right, traversal + "right")
            print(traversal + node!.value)
        }
    }
}
```

### Explanation:

- **Node Struct**: Represents each node in the BST with a value and pointers to left and right children.
- **BinarySearchTree Class**: Manages the BST with methods for insertion, deletion, and traversal.
- **Insertion**: Adds a new node to the correct position in the BST.
- **Deletion**: Removes a node while maintaining BST properties.
- **Traversals**:
  - **Pre-order**: Visits the node first, then the left subtree, then the right subtree.
  - **In-order**: Visits the left subtree, then the node, then the right subtree.
  - **Post-order**: Visits the left subtree, then the right subtree, then the node.

This implementation is efficient with time complexity of **O(log n)** for insert and delete operations in a balanced tree, and **O(n)** in the worst case for unbalanced trees.

