use strict;
use warnings;

# Function to merge two sorted arrays into one sorted array in descending order
sub merge {
    my ($arr1, $arr2) = @_;
    my @merged;

    # Merge the two arrays while maintaining order
    while (scalar @$arr1 > 0 && scalar @$arr2 > 0) {
        if ($arr1->[0] > $arr2->[0]) {
            push @merged, $arr1->[0];
            shift @$arr1;
        } else {
            push @merged, $arr2->[0];
            shift @$arr2;
        }
    }

    # Add remaining elements from either array
    while (scalar @$arr1 > 0) {
        push @merged, shift @$arr1;
    }
    while (scalar @$arr2 > 0) {
        push @merged, shift @$arr2;
    }

    return \@merged;
}

# Function to perform merge sort on an array
sub merge_sort {
    my ($arr) = @_;
    return $arr if @$arr <= 1;

    my $mid = scalar div($# $arr, 2);
    my $left = merge_sort( $arr->[@$arr[0..$mid-1]] );
    my $right = merge_sort( $arr->[@$arr[$mid..$# $arr]] );

    return merge($left, $right);
}

# Main program
sub main {
    print "Enter integers (end with 'exit'):\n";

    my @numbers;
    while (1) {
        my $input = <>;
        chomp $input;

        if ($input eq 'exit') {
            last;
        }

        if (!grep { /^\d+$/ } $input) {
            die "Invalid input: Please enter integers only.\n";
        }

        push @numbers, $input;
    }

    # Sort the array in descending order using merge sort
    my $sorted = merge_sort( \@numbers );

    # Print the sorted array
    print "Sorted array in descending order:\n";
    foreach my $num (@$sorted) {
        print "$num\n";
    }
}

# Run the main program
main();
```

### Explanation:

- **`merge`**: Merges two sorted arrays into one sorted array in descending order.
- **`merge_sort`**: Recursively sorts an array using merge sort.
- **`main`**: Handles user input, validates input, and prints the sorted array.
- **Edge Cases Handled**:
  - Empty input.
  - Non-integer input.
  - Input that ends with `'exit'` to exit the program.
- **Efficiency**: Merge sort has a time complexity of O(n log n), which is efficient for large arrays.

